class Solution(object):
    def maximumSumOfHeights(self, heights):
        n = len(heights)
        best = 0
        for peak in range(n):
            total = heights[peak]
            cur = heights[peak]
            for i in range(peak - 1, -1, -1):
                cur = min(cur, heights[i])
                total += cur
            cur = heights[peak]
            for i in range(peak + 1, n):
                cur = min(cur, heights[i])
                total += cur
            best = max(best, total)
        return best
